 1	import React, { FC, Ref, useState } from 'react';
 2	
 3	import { Dropdown, DropdownItem, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 4	import { NetworkPolicyPort } from '@utils/models';
 5	
 6	type NetworkPolicyPortsDropdownProps = {
 7	  index: number;
 8	  onSingleChange: (port: NetworkPolicyPort, index: number) => void;
 9	  port: NetworkPolicyPort;
10	};
11	
12	const NetworkPolicyPortsDropdown: FC<NetworkPolicyPortsDropdownProps> = ({
13	  index,
14	  onSingleChange,
15	  port,
16	}) => {
17	  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
18	
19	  return (
20	    <Dropdown
21	      data-test="port-protocol"
22	      isOpen={isDropdownOpen}
23	      onSelect={(_event, protocol) => {
24	        setIsDropdownOpen(false);
25	        onSingleChange({ ...port, protocol: protocol?.toString() }, index);
26	      }}
27	      selected={port?.protocol}
28	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
29	        <MenuToggle
30	          id={`toggle-${port.key}-${index}`}
31	          isExpanded={isDropdownOpen}
32	          onClick={() => setIsDropdownOpen(!isDropdownOpen)}
33	          ref={toggleRef}
34	        >
35	          {port?.protocol}
36	        </MenuToggle>
37	      )}
38	    >
39	      <DropdownItem value="TCP">TCP</DropdownItem>
40	      <DropdownItem value="UDP">UDP</DropdownItem>
41	      <DropdownItem value="SCTP">SCTP</DropdownItem>
42	    </Dropdown>
43	  );
44	};
45	
46	export default NetworkPolicyPortsDropdown;

